import React from 'react';

const WhatsAppFloat = () => {
  return (
    <a 
      href="https://wa.me/94702933408" 
      className="wa-float" 
      target="_blank" 
      rel="noopener noreferrer"
      aria-label="Contact us on WhatsApp"
    >
      <i className="fa-brands fa-whatsapp"></i>
    </a>
  );
};

export default WhatsAppFloat;
